        if (this.border) {
          cssAct['box-shadow'] = '0 2px 5px 0 rgba(0, 0, 0, 0.16), 0 2px 10px 0 rgba(0, 0, 0, 0.12)';
          cssAct['border-radius'] = '2px';
          cssAct['color'] = '#272727';
        }

        if (this.act.activityBgGradient) {
          cssAct['background-image'] = this.act.activityBgGradient.getCss();
        }
